mapper.select:
SELECT EXISTS
(
  SELECT *
  FROM fx_country
  WHERE code = #{code}
)

mapper.update:
UPDATE fx_country
SET
   name = #{name}
  ,currency_code = #{currencyCode}
  ,name_en = #{nameEn}
  ,name_short = #{nameShort}
  ,sort_order = #{sortOrder}
  ,updated_at = #{updatedAt}
  ,updated_by = #{updatedBy}
WHERE code = #{code}

UPDATE fx_country
SET
   code = #{country.code}
  ,name = #{country.name}
  ,currency_code = #{country.currencyCode}
  ,name_en = #{country.nameEn}
  ,name_short = #{country.nameShort}
  ,sort_order = #{country.sortOrder}
  ,updated_at = #{country.updatedAt}
  ,updated_by = #{country.updatedBy}
WHERE code = #{code}
